function MapView() {

  return (

    <div className="card">

      <h2>Map View</h2>

      <iframe
        title="map"
        width="100%"
        height="300"
        loading="lazy"
        allowFullScreen
        src="https://maps.google.com/maps?q=India&t=&z=4&ie=UTF8&iwloc=&output=embed"
      ></iframe>

    </div>
  );
}

export default MapView;
